#include <iostream>

class MathOperations {
public:
    int multiply(int a, int b) {
        return a * b;
    }

    double multiply(double a, double b, double c) {
        return a * b * c;
    }
};

int main() {
    MathOperations math;
    std::cout << math.multiply(5, 10) << std::endl;
    std::cout << math.multiply(2.5, 3.0, 4.0) << std::endl;
    return 0;
}
